function ov(a,b){return Math.max(0,Math.min(a.x+a.w,b.x+b.w)-Math.max(a.x,b.x))*Math.max(0,Math.min(a.y+a.h,b.y+b.h)-Math.max(a.y,b.y))}
function clipR(r,w,h){const x=Math.max(0,Math.round(r.x)),y=Math.max(0,Math.round(r.y)),x2=Math.min(w,Math.round(r.x+r.w)),y2=Math.min(h,Math.round(r.y+r.h));return{x,y,w:Math.max(0,x2-x),h:Math.max(0,y2-y)}}
function innerCardBoxes(pg){const cs=comps(pg,white,{x:0,y:pg.height*.18,w:pg.width,h:pg.height*.80},4,350).filter(r=>r.w>pg.width*.11&&r.h>pg.height*.08&&r.w<pg.width*.35&&r.h<pg.height*.30);cs.sort((a,b)=>a.y-b.y||a.x-b.x);const out=[];for(const r of cs)if(out.every(o=>ov(o,r)<Math.min(o.w*o.h,r.w*r.h)*.25))out.push(r);return out}
function blueFrame(r,g,b){const mx=Math.max(r,g,b),mn=Math.min(r,g,b);return b>70&&mx-mn>45&&b-r>35&&(b>=g||g-r>18)}
function smooth3(a){const o=new Float64Array(a.length);for(let i=0;i<a.length;i++)o[i]=((a[i-1]??a[i])+a[i]+(a[i+1]??a[i]))/3;return o}
function scoreAxis(c,axis,a0,a1){const w=c.width,h=c.height,d=c.getContext('2d',{willReadFrequently:true}).getImageData(0,0,w,h).data,out=new Float64Array(axis==='y'?h:w);if(axis==='y'){const lo=Math.max(0,a0|0),hi=Math.min(w,a1|0),den=Math.max(1,hi-lo);for(let y=0;y<h;y++){let n=0;for(let x=lo;x<hi;x++){const i=(y*w+x)*4;if(blueFrame(d[i],d[i+1],d[i+2]))n++}out[y]=n/den}}else{const lo=Math.max(0,a0|0),hi=Math.min(h,a1|0),den=Math.max(1,hi-lo);for(let x=0;x<w;x++){let n=0;for(let y=lo;y<hi;y++){const i=(y*w+x)*4;if(blueFrame(d[i],d[i+1],d[i+2]))n++}out[x]=n/den}}return smooth3(out)}
function scoreBands(scores,threshold,lo=0,hi=scores.length,minw=2){const out=[];let i=Math.max(0,lo|0),end=Math.min(scores.length,hi|0);while(i<end){if(scores[i]<threshold){i++;continue}let j=i+1,sum=scores[i],mx=scores[i],ws=scores[i]*i,wt=scores[i];while(j<end&&scores[j]>=threshold){sum+=scores[j];mx=Math.max(mx,scores[j]);ws+=scores[j]*j;wt+=scores[j];j++}if(j-i>=minw)out.push({start:i,end:j-1,center:wt?ws/wt:(i+j-1)/2,score:sum/(j-i),max:mx});i=j}return out}
function pickBand(bands,a,b,expected){let cand=bands.filter(x=>x.end>=a&&x.start<=b);if(!cand.length)return null;const mx=Math.max(...cand.map(x=>x.max));cand=cand.filter(x=>x.max>=mx*.8);return cand.sort((x,y)=>Math.abs(x.center-expected)-Math.abs(y.center-expected))[0]}
function rowGroups(boxes){const rows=[];for(const b of [...boxes].sort((a,b)=>a.y-b.y||a.x-b.x)){const cy=b.y+b.h/2;let row=rows.find(r=>Math.abs(cy-r.cy)<28);if(!row){row={cy,boxes:[]};rows.push(row)}row.boxes.push(b);row.cy=row.boxes.reduce((s,x)=>s+x.y+x.h/2,0)/row.boxes.length}for(const r of rows)r.boxes.sort((a,b)=>a.x-b.x);rows.sort((a,b)=>a.cy-b.cy);return rows}
function median(a){const s=[...a].sort((a,b)=>a-b),m=Math.floor(s.length/2);return s.length%2?s[m]:(s[m-1]+s[m])/2}
function stableGridBoxes(pg){const w=pg.width,h=pg.height,anchors=innerCardBoxes(pg),rows=rowGroups(anchors);if(!rows.length)throw Error('ไม่พบการ์ดสำหรับล็อกกริด');const hs=scoreAxis(pg,'y',w*.025,w*.975),hBands=scoreBands(hs,.56,h*.17,h,2),yb=[];const firstY=Math.min(...rows[0].boxes.map(b=>b.y));let band=pickBand(hBands,Math.max(h*.17,firstY-25),firstY+25,firstY);yb.push(Math.round(band?band.start:Math.max(0,firstY-4)));for(let i=0;i<rows.length-1;i++){const py=median(rows[i].boxes.map(b=>b.y+b.h)),ny=median(rows[i+1].boxes.map(b=>b.y));band=pickBand(hBands,py-20,ny+60,(py+ny)/2);yb.push(Math.round(band?band.center:(py+ny)/2))}const ly=median(rows.at(-1).boxes.map(b=>b.y+b.h));band=pickBand(hBands,ly-10,h-1,ly+40);yb.push(Math.round(band?band.start:Math.min(h,ly+20)));for(let i=1;i<yb.length;i++)yb[i]=Math.max(yb[i],yb[i-1]+80);const raw=[];for(let ri=0;ri<rows.length;ri++){const row=rows[ri],y0=yb[ri],y1=yb[ri+1],actual=row.boxes.length,medw=median(row.boxes.map(b=>b.w)),layout=medw<w*.19?5:4,vs=scoreAxis(pg,'x',y0,y1),bands=scoreBands(vs,.55,w*.02,w*.99,2).filter(b=>b.max>.55);let full=null;if(bands.length>=2){const left=bands[0],right=bands.at(-1),expected=Array.from({length:layout+1},(_,i)=>left.center+(right.center-left.center)*i/layout),chosen=[];let valid=true;for(const ex of expected){const c=[...bands].sort((a,b)=>Math.abs(a.center-ex)-Math.abs(b.center-ex)).find(b=>chosen.every(q=>Math.abs(b.center-q.center)>10));const tol=(right.center-left.center)/layout*.22;if(!c||Math.abs(c.center-ex)>tol){valid=false;break}chosen.push(c)}chosen.sort((a,b)=>a.center-b.center);if(valid&&chosen.length===layout+1){const p=[];for(let i=1;i<chosen.length;i++)p.push(chosen[i].center-chosen[i-1].center);if(Math.max(...p)-Math.min(...p)<median(p)*.12)full=chosen.map(b=>Math.round(b.center))}}raw.push({row,y0,y1,actual,layout,full})}const templates={};for(const n of[4,5]){const arr=raw.filter(r=>r.layout===n&&r.full).map(r=>r.full);templates[n]=arr.length?Array.from({length:n+1},(_,i)=>Math.round(median(arr.map(a=>a[i])))):Array.from({length:n+1},(_,i)=>Math.round(w*.036+(w*.964-w*.036)*i/n))}const out=[];for(const r of raw){const t=templates[r.layout],full=r.full?r.full.map((x,i)=>Math.abs(x-t[i])<=8?Math.round((x+t[i])/2):t[i]):[...t],xb=full.slice(0,r.actual+1);for(let i=0;i<r.actual;i++)out.push({x:xb[i],y:r.y0,w:xb[i+1]-xb[i],h:r.y1-r.y0,gridLocked:true})}const ordered=rows.flatMap(r=>r.boxes);if(out.length!==ordered.length)throw Error(`จำนวนกรอบ ${out.length} ไม่ตรง anchor ${ordered.length}`);for(let i=0;i<out.length;i++){const r=out[i],a=ordered[i],cx=a.x+a.w/2,cy=a.y+a.h/2;if(!(cx>=r.x&&cx<r.x+r.w&&cy>=r.y&&cy<r.y+r.h))throw Error(`กริดใบ ${i+1} ไม่ครอบ anchor`);let inside=0;for(const q of ordered){const x=q.x+q.w/2,y=q.y+q.h/2;if(x>=r.x&&x<r.x+r.w&&y>=r.y&&y<r.y+r.h)inside++}if(inside!==1)throw Error(`กริดใบ ${i+1} มี anchor ${inside}`)}return out}
